#!/usr/bin/env python3
"""
Monitoring script for the web application
"""

import requests
import time
import json
from datetime import datetime

def check_health():
    """Check the health endpoint of the application"""
    try:
        response = requests.get('http://localhost:3000/health', timeout=5)
        return {
            'endpoint': '/health',
            'status_code': response.status_code,
            'response_time': response.elapsed.total_seconds(),
            'timestamp': datetime.now().isoformat(),
            'healthy': response.status_code == 200
        }
    except Exception as e:
        return {
            'endpoint': '/health',
            'error': str(e),
            'timestamp': datetime.now().isoformat()
        }

def check_users():
    """Check the users endpoint of the application"""
    try:
        response = requests.get('http://localhost:3000/users', timeout=5)
        return {
            'endpoint': '/users',
            'status_code': response.status_code,
            'response_time': response.elapsed.total_seconds(),
            'timestamp': datetime.now().isoformat(),
            'healthy': response.status_code == 200
        }
    except Exception as e:
        return {
            'endpoint': '/users',
            'error': str(e),
            'timestamp': datetime.now().isoformat()
        }

def main():
    print("Starting monitoring...")

    # Check health endpoint
    health_result = check_health()
    print(f"Health check: {health_result}")

    # Check users endpoint
    users_result = check_users()
    print(f"Users check: {users_result}")

    # Log results to file
    with open('monitoring_log.json', 'a') as f:
        f.write(json.dumps(health_result) + '\n')
        f.write(json.dumps(users_result) + '\n')

if __name__ == "__main__":
    main()

